solution: ```class Solution {
    public int primePalindrome(int n) {
        if (n <= 2) return 2;
        int candidate = n;
        while (true) {
            if (isPalindrome(candidate) && isPrime(candidate)) return candidate;
            candidate++;
            if (10_000_000 < candidate && candidate < 100_000_000) candidate = 100_000_000;
        }
    }

    private boolean isPalindrome(int x) {
        int rev = 0, t = x;
        while (t != 0) {
            rev = rev * 10 + t % 10;
            t /= 10;
        }
        return rev == x;
    }

    private boolean isPrime(int x) {
        if (x < 2 || (x % 2 == 0 && x != 2)) return false;
        for (int i = 3; i * i <= x; i += 2) {
            if (x % i == 0) return false;
        }
        return true;
    }
}
```
